  '77_5':  { example2: "Anti-discrimination laws aim to protect workers from unfair treatment in the workplace.", example2Kr: "반차별 법은 직장에서 불공정한 대우로부터 근로자들을 보호하는 것을 목표로 한다." },
  '77_6':  { example2: "The egalitarian school model places equal value on academic and vocational learning.", example2Kr: "평등주의적 학교 모델은 학문적 학습과 직업적 학습에 동등한 가치를 부여한다." },
  '77_7':  { example2: "Women's empowerment through education has strong links to reducing child mortality rates.", example2Kr: "교육을 통한 여성의 역량 강화는 영아 사망률 감소와 강한 연관성이 있다." },
  '77_8':  { example2: "The ethnography immersed the researcher in the daily routines of a nomadic community.", example2Kr: "민족지학 연구가 연구자를 유목 공동체의 일상 속에 완전히 몰입시켰다." },
  '77_9':  { example2: "Globalisation has accelerated the spread of English as the dominant language of trade.", example2Kr: "세계화가 무역의 지배적 언어로서 영어의 확산을 가속화했다." },
  '77_10': { example2: "Hypothesis testing allows social scientists to draw statistically valid conclusions from data.", example2Kr: "가설 검증은 사회과학자들이 데이터로부터 통계적으로 유효한 결론을 도출할 수 있게 한다." },
  '77_11': { example2: "Rising inequality undermines social trust and increases political polarisation.", example2Kr: "증가하는 불평등은 사회적 신뢰를 약화시키고 정치적 양극화를 심화시킨다." },
  '77_12': { example2: "Successful integration requires adequate support services for newcomer communities.", example2Kr: "성공적인 통합을 위해서는 신규 이주민 공동체를 위한 충분한 지원 서비스가 필요하다." },
  '77_13': { example2: "Financial literacy should be taught in schools to prepare young people for adult life.", example2Kr: "금융 리터러시는 청소년들이 성인 생활을 준비할 수 있도록 학교에서 가르쳐야 한다." },
  '77_14': { example2: "Breaking social norms can signal creativity but may also invite disapproval or exclusion.", example2Kr: "사회 규범을 어기는 것은 창의성을 나타낼 수 있지만 불승인이나 배제를 초래할 수도 있다." },
  '77_15': { example2: "Modern pedagogy encourages students to question ideas rather than passively accept them.", example2Kr: "현대 교수법은 학생들이 수동적으로 받아들이기보다 아이디어에 의문을 제기하도록 장려한다." },
  '77_16': { example2: "Early socialisation in the family and school shapes lifelong attitudes and behaviours.", example2Kr: "가족과 학교에서의 초기 사회화는 평생의 태도와 행동을 형성한다." },
  '77_17': { example2: "Education programmes can challenge stereotypes by exposing students to diverse perspectives.", example2Kr: "교육 프로그램은 학생들에게 다양한 관점을 접하게 함으로써 고정관념에 도전할 수 있다." },
  '77_18': { example2: "Social stratification based on birth remains entrenched in many parts of the world.", example2Kr: "출생에 기반한 사회 계층화는 세계 많은 지역에서 여전히 뿌리 깊게 남아 있다." },
